def gap_first_pair_sum_transfer(anchor, candidates, context):
    """Rank short combinations by amount gap first, then time span."""
    ranked = []
    ordered = sorted(candidates, key=lambda item: event_time(item))
    for i, first in enumerate(ordered):
        ranked.append(make_result("gap_first_pair_sum_transfer", anchor, [first], context, 0.80))
        for second in ordered[i + 1: min(len(ordered), i + context.subset_pool_size)]:
            ranked.append(make_result("gap_first_pair_sum_transfer", anchor, [first, second], context, 0.84))
    ranked.sort(key=lambda result: (Decimal(result.amount_gap), result.time_gap_hours))
    return ranked[:context.top_k]
